"""LEVER B — the task-derived SOURCE-ELIGIBILITY plan builder.

This is the FOUNDATION of Batch 1: it takes the constraints the RQ *itself* states
(``source_types`` / ``languages`` / ``recency``), parsed generically from the prompt by
``instruction/constraint_extractor.py`` and cached on ``protocol['_rq_constraints']``, and
turns them into a per-URL DEMOTE map at the citable-generation-pool boundary.

It is a strict GENERALIZATION of the PROVEN date-window / scope WEIGHT seam
(``evidence_selector._select_evidence_for_generation_impl``): build a per-URL multiplicative
demote weight in ``(0, 1]`` + a tail-partition set + disclosed exclusion records, and fold the
weight into the SAME selection sort key. Nothing is hard-dropped (DNA §-1.3 WEIGHT-not-FILTER):
an ineligible row (wrong source-type / non-English / out-of-recency) is DEMOTED, tail-partitioned,
KEPT in the corpus, and disclosed; an UNRESOLVED row (unknown genre / unknown language / undated)
is FAIL-OPEN (weight 1.0, never punished) and flagged for fetch recovery.

Generalization (hard rule): every constraint is read from the RQ's OWN parsed words — there are NO
task-72 literals (no "journal-only pre-2023", no clinical/AI-labor branches). The source-type
vocabulary is the SAME canonical vocabulary ``constraint_extractor`` already emits for ANY prompt,
and the genre classifier is the field-agnostic ``document_type_classifier``. An RQ that states no
source/language/recency constraint yields an EMPTY plan (byte-identical selection).

Default OFF: ``PG_RQ_SOURCE_ELIGIBILITY_ENFORCE`` empty/falsey => ``build_rq_eligibility`` returns
an EMPTY plan => the selection sort key + tail partition are byte-identical. No post-generation
entailment/verification/sentence-drop gate is added (upstream-only, LAW/DNA-compliant).
"""
from __future__ import annotations

import logging
import re
from dataclasses import dataclass, field
from typing import Any, Mapping

from src.polaris_graph.settings import resolve
from src.polaris_graph.retrieval.document_type_classifier import (
    DocumentType,
    classify_document_type,
)

logger = logging.getLogger("polaris_graph.rq_eligibility")

_ENFORCE_FLAG = "PG_RQ_SOURCE_ELIGIBILITY_ENFORCE"
_DEMOTE_WEIGHT_FLAG = "PG_RQ_SOURCE_ELIGIBILITY_DEMOTE_WEIGHT"
_OFF_VALUES = frozenset({"0", "false", "no", "off", "disabled", ""})
_ON_VALUES = frozenset({"1", "true", "yes", "on", "enabled"})

# Mirror of the date/scope demote default: an ineligible row is KEPT at a low weight, never zeroed.
_DEFAULT_DEMOTE_WEIGHT = 0.3

_YEAR_RE = re.compile(r"\b(19|20|21)\d{2}\b")


# ── Canonical RQ source-type  ->  the DocumentType GENRE family it admits ────────────────────
# Keys are the SAME canonical tokens ``constraint_extractor._SOURCE_TYPE_ALIASES`` emits for any
# prompt (journal_article, peer_reviewed, news_article, ...). A row is ELIGIBLE under a stated
# source-type constraint iff its classified genre is in the UNION of the admitted families across
# every stated type. Field-agnostic; no task literals.
_SOURCE_TYPE_TO_GENRES: dict[str, frozenset[DocumentType]] = {
    "journal_article": frozenset({DocumentType.JOURNAL_ARTICLE, DocumentType.REVIEW_ARTICLE}),
    "peer_reviewed": frozenset({DocumentType.JOURNAL_ARTICLE, DocumentType.REVIEW_ARTICLE}),
    "conference_paper": frozenset({DocumentType.CONFERENCE_PAPER}),
    "working_paper": frozenset({DocumentType.WORKING_PAPER}),
    "preprint": frozenset({DocumentType.PREPRINT}),
    "book": frozenset({DocumentType.BOOK}),
    "book_chapter": frozenset({DocumentType.BOOK}),
    "report": frozenset({DocumentType.REPORT}),
    "government_report": frozenset({DocumentType.REPORT}),
    "news_article": frozenset({DocumentType.NEWS, DocumentType.PRESS_RELEASE}),
    "blog_post": frozenset({DocumentType.BLOG_COMMENTARY}),
    "website": frozenset({DocumentType.BLOG_COMMENTARY, DocumentType.ENCYCLOPEDIA}),
    "grey_literature": frozenset(
        {DocumentType.REPORT, DocumentType.WORKING_PAPER, DocumentType.PREPRINT}
    ),
}


def eligibility_enabled() -> bool:
    """LEVER B kill-switch. DEFAULT OFF (operator activates on the slate). OFF =>
    ``build_rq_eligibility`` returns an EMPTY plan => byte-identical selection."""
    raw = (resolve(_ENFORCE_FLAG) or "").strip().lower()
    return raw not in _OFF_VALUES


def demote_weight() -> float:
    """The multiplicative ranking demote for an INELIGIBLE row (LAW VI overridable). Clamped to
    (0, 1) — a demoted source is KEPT at low weight, never zero/dropped (mirrors the date/scope
    demote)."""
    raw = (resolve(_DEMOTE_WEIGHT_FLAG) or "").strip()
    if not raw:
        return _DEFAULT_DEMOTE_WEIGHT
    try:
        val = float(raw)
    except (TypeError, ValueError):
        return _DEFAULT_DEMOTE_WEIGHT
    return min(max(val, 0.01), 0.99)


@dataclass
class RQEligibilityPlan:
    """The demote / disclose / fetch-recovery decisions for one corpus under one RQ's stated
    source/language/recency intent. Empty plan => byte-identical widest+deepest run."""

    url_to_eligibility_weight: dict[str, float] = field(default_factory=dict)
    ineligible_urls: set[str] = field(default_factory=set)
    fetch_recovery_urls: set[str] = field(default_factory=set)
    eligibility_records: list[dict[str, Any]] = field(default_factory=list)

    def is_empty(self) -> bool:
        return not (self.url_to_eligibility_weight or self.ineligible_urls)


def _field(source: "Any", *names: str) -> "Any":
    if isinstance(source, Mapping):
        for n in names:
            if n in source and source.get(n) is not None:
                return source.get(n)
        return None
    for n in names:
        v = getattr(source, n, None)
        if v is not None:
            return v
    return None


def _row_url(row: "Any") -> str:
    return str(_field(row, "source_url", "url") or "")


def _row_year(row: "Any") -> "int | None":
    """Best-effort explicit publication year, or None (undated => fail-open)."""
    for key in ("year", "publication_year", "pub_date", "publication_date", "published", "date"):
        v = _field(row, key)
        if v is None:
            continue
        m = _YEAR_RE.search(str(v))
        if m:
            try:
                return int(m.group(0))
            except (TypeError, ValueError):
                continue
    meta = _field(row, "metadata")
    if isinstance(meta, Mapping):
        v = meta.get("year")
        if v is not None:
            m = _YEAR_RE.search(str(v))
            if m:
                try:
                    return int(m.group(0))
                except (TypeError, ValueError):
                    return None
    return None


def _row_language(row: "Any") -> "str | None":
    """Best-effort ISO-639-1 language of a row, or None (unknown => fail-open). Reads a row's
    own ``language``/``lang`` sidecar (or ``metadata.language``); NO network, NO detection —
    an absent signal is treated as UNKNOWN, never as a violation."""
    for key in ("language", "lang"):
        v = _field(row, key)
        if v:
            s = str(v).strip().lower()
            if s:
                return s[:2]
    meta = _field(row, "metadata")
    if isinstance(meta, Mapping):
        v = meta.get("language") or meta.get("lang")
        if v:
            s = str(v).strip().lower()
            if s:
                return s[:2]
    return None


def _row_genre(row: "Any") -> DocumentType:
    """Classify a row's document GENRE, reusing the field-agnostic deterministic classifier.
    Prefers a pre-stamped ``document_type`` (from tier_classifier) and otherwise runs the
    offline host/url/DOI classifier. Fail-open to UNKNOWN on any error (never punished)."""
    pre = _field(row, "document_type")
    if pre is not None:
        try:
            return DocumentType(str(pre))
        except (ValueError, TypeError):
            pass
    try:
        dt, _basis = classify_document_type(
            openalex_publication_type=str(_field(row, "openalex_publication_type") or ""),
            openalex_source_type=str(_field(row, "openalex_source_type") or ""),
            source_class=str(_field(row, "source_class") or ""),
            url=_row_url(row),
            title=str(_field(row, "title") or ""),
            doi=str(_field(row, "doi") or ""),
        )
        return dt
    except Exception:  # noqa: BLE001 - fail-open: an unclassifiable row is UNKNOWN (neutral)
        return DocumentType.UNKNOWN


def _admitted_genres(source_types: list[str]) -> "frozenset[DocumentType] | None":
    """Union of the admitted genres across the RQ's stated canonical source types. Returns None
    when NONE of the stated types map to a known genre family (=> source-type is UNRESOLVED =>
    no source-type demotion, fail-open)."""
    admitted: set[DocumentType] = set()
    resolved_any = False
    for st in source_types or []:
        fam = _SOURCE_TYPE_TO_GENRES.get(str(st).strip().lower())
        if fam:
            admitted |= set(fam)
            resolved_any = True
    return frozenset(admitted) if resolved_any else None


def build_rq_eligibility(
    protocol: "dict[str, Any] | None",
    evidence_rows: "list[Any] | None",
) -> RQEligibilityPlan:
    """Build the RQ-source-eligibility plan for one corpus (LEVER B).

    Reads the constraints the RQ itself stated from ``protocol['_rq_constraints']`` (the
    ``constraint_extractor`` output: ``source_types`` / ``languages`` / ``recency``) and demotes
    each citable row that is DEFINITIVELY ineligible under one of them. Returns an EMPTY plan when
    the enforce flag is OFF, when no RQ constraints are cached, or when the RQ states no
    source/language/recency constraint (byte-identical). Pure; never raises."""
    plan = RQEligibilityPlan()
    if not eligibility_enabled():
        return plan
    if not protocol:
        return plan
    rows = list(evidence_rows or [])
    if not rows:
        return plan

    rq = protocol.get("_rq_constraints")
    if not isinstance(rq, Mapping):
        return plan

    source_types = [str(x) for x in (rq.get("source_types") or []) if str(x).strip()]
    languages = [str(x).strip().lower()[:2] for x in (rq.get("languages") or []) if str(x).strip()]
    recency = rq.get("recency")

    admitted = _admitted_genres(source_types)
    # A recency phrase like "since 2020" / "last 5 years (2020-2025)" -> the MIN stated 4-digit
    # year is the enforced floor. FAIL-OPEN on a purely relative phrase carrying no resolvable
    # year (no bound the classifier can prove a violation against).
    recency_floor: "int | None" = None
    if recency:
        _full = re.findall(r"\b(?:19|20|21)\d{2}\b", str(recency))
        if _full:
            try:
                recency_floor = min(int(y) for y in _full)
            except (TypeError, ValueError):
                recency_floor = None

    have_constraint = bool(admitted or languages or recency_floor is not None)
    if not have_constraint:
        return plan

    _dw = demote_weight()

    for row in rows:
        url = _row_url(row)
        if not url:
            continue

        ineligible_reasons: list[str] = []
        unresolved = False

        # ── source-type eligibility ──
        if admitted is not None:
            genre = _row_genre(row)
            if genre == DocumentType.UNKNOWN:
                unresolved = True  # unknown genre => fail-open, flag for fetch recovery
            elif genre not in admitted:
                ineligible_reasons.append(
                    f"source_type: genre={genre.value} not in requested "
                    f"{sorted(g.value for g in admitted)}"
                )

        # ── language eligibility (fail-open when unknown) ──
        if languages:
            lang = _row_language(row)
            if lang is None:
                unresolved = True  # unknown language => fail-open
            elif lang not in languages:
                ineligible_reasons.append(
                    f"language: row={lang} not in requested {languages}"
                )

        # ── recency eligibility (fail-open when undated) ──
        if recency_floor is not None:
            yr = _row_year(row)
            if yr is None:
                unresolved = True  # undated => fail-open
            elif yr < recency_floor:
                ineligible_reasons.append(
                    f"recency: year={yr} < floor={recency_floor}"
                )

        if ineligible_reasons:
            plan.url_to_eligibility_weight[url] = _dw
            plan.ineligible_urls.add(url)
            plan.eligibility_records.append({
                "source_url": url,
                "action": "demoted_ineligible_kept",
                "weight": _dw,
                "reasons": ineligible_reasons,
            })
        elif unresolved:
            # KEPT at full weight (fail-open), but flagged so the operator can fetch-recover the
            # missing genre/language/date signal (disclosure, NOT a demote or drop).
            plan.fetch_recovery_urls.add(url)

    if not plan.is_empty():
        logger.info(
            "[rq_eligibility] LEVER B: demoted=%d ineligible source(s) "
            "(kept at weight=%.2f, sorted last — §-1.3 disclose, NOT dropped); "
            "flagged_for_fetch_recovery=%d (source_types=%s languages=%s recency_floor=%s)",
            len(plan.url_to_eligibility_weight), _dw, len(plan.fetch_recovery_urls),
            source_types or None, languages or None, recency_floor,
        )
    return plan

"""LEVER B — upstream CITATION RE-ANCHORING (primary-source grounding selection).

When a claim sentence's cited ``[#ev]`` token points at a SECONDARY source (e.g. a news article
or blog restating a finding) but a PRIMARY row for the SAME fact — same normalized finding /
numbers, higher credibility tier, journal-genre and/or a resolved DOI — exists in the SAME
evidence pool, this helper re-points the sentence's grounding token to the PRIMARY row.

This is an UPSTREAM grounding-SOURCE selection performed BEFORE strict_verify runs. It is NOT a
post-generation entailment / verification / sentence-drop / filtering gate: it never removes a
sentence, never drops a citation, never edits prose beyond swapping ONE evidence id for a
strictly-better one that grounds the SAME numbers. If no better primary exists, the token is left
exactly as-is.

Generalization: "primary vs secondary" is decided GENERICALLY from each row's tier + document
genre + DOI presence (via the field-agnostic classifiers) and a numeric/keyword-overlap match of
the claim's own content — there are NO task literals. The re-anchor target must corroborate the
SAME salient numbers the sentence states, so the swap can only ever strengthen grounding.

Default OFF: ``PG_CITATION_REANCHOR_PRIMARY`` empty/falsey => ``reanchor_citation`` /
``reanchor_sentences`` return their input UNCHANGED (byte-identical tokens).
"""
from __future__ import annotations

import logging
import re
from typing import Any, Callable, Mapping, Optional, Sequence

from src.polaris_graph.settings import resolve

logger = logging.getLogger("polaris_graph.citation_reanchor")

_ENABLE_FLAG = "PG_CITATION_REANCHOR_PRIMARY"
_OFF_VALUES = frozenset({"0", "false", "no", "off", "disabled", ""})

# Tier ordinal: lower = stronger (mirrors evidence_selector._TIER_PRIORITY).
_TIER_PRIORITY: dict[str, int] = {
    "T1": 1, "T2": 2, "T3": 3, "T4": 4, "T5": 5, "T6": 6, "T7": 7, "UNKNOWN": 8,
}

_NUM_RE = re.compile(r"-?\d+(?:\.\d+)?%?")
_WORD_RE = re.compile(r"[A-Za-z][A-Za-z0-9\-]{2,}")


def reanchor_enabled() -> bool:
    """LEVER B re-anchoring kill-switch. DEFAULT OFF => the re-anchor functions are no-ops =>
    every ``[#ev]`` token is byte-identical."""
    raw = (resolve(_ENABLE_FLAG) or "").strip().lower()
    return raw not in _OFF_VALUES


def _get(row: "Any", *names: str) -> "Any":
    if isinstance(row, Mapping):
        for n in names:
            if n in row and row.get(n) is not None:
                return row.get(n)
        return None
    for n in names:
        v = getattr(row, n, None)
        if v is not None:
            return v
    return None


def _tier_rank(row: "Any") -> int:
    return _TIER_PRIORITY.get(str(_get(row, "tier") or "UNKNOWN"), 8)


def _has_doi(row: "Any") -> bool:
    return bool(str(_get(row, "doi") or "").strip())


def _is_primary_genre(row: "Any") -> bool:
    """True when the row's document genre is a PRIMARY scholarly genre. Reads a pre-stamped
    ``document_type`` / ``is_journal_article`` sidecar; fail-open False when unknown (an unknown
    genre is never treated as a stronger primary)."""
    ij = _get(row, "is_journal_article")
    if ij is True:
        return True
    dt = str(_get(row, "document_type") or "").upper()
    return dt in ("JOURNAL_ARTICLE", "REVIEW_ARTICLE", "PREPRINT", "CONFERENCE_PAPER", "WORKING_PAPER")


def _row_text(row: "Any") -> str:
    return " ".join(
        str(_get(row, k) or "") for k in ("statement", "direct_quote", "quote", "text", "title")
    )


def _numbers(text: str) -> set[str]:
    return {m.rstrip("%") for m in _NUM_RE.findall(text or "")}


def _keywords(text: str) -> set[str]:
    return {w.lower() for w in _WORD_RE.findall(text or "")}


def is_more_primary(candidate: "Any", current: "Any") -> bool:
    """True iff ``candidate`` is a STRICTLY stronger primary grounding source than ``current``:
    a better (lower) tier, OR same tier with a primary scholarly genre / resolved DOI the current
    lacks. Conservative — ties that don't strictly improve return False (no swap)."""
    ct, rt = _tier_rank(candidate), _tier_rank(current)
    if ct < rt:
        return True
    if ct > rt:
        return False
    # same tier: prefer a primary-genre / DOI-bearing row over one without.
    cand_primary = _is_primary_genre(candidate) or _has_doi(candidate)
    cur_primary = _is_primary_genre(current) or _has_doi(current)
    return cand_primary and not cur_primary


def _same_fact(sentence: str, current: "Any", candidate: "Any") -> bool:
    """True iff ``candidate`` grounds the SAME salient fact as the sentence + current source.
    Requires every SALIENT number stated in the sentence to also appear in the candidate (so the
    swap can only ground the SAME figures) AND a minimal keyword overlap. When the sentence states
    no numbers, falls back to a keyword-overlap floor against the current+candidate. Conservative:
    an ambiguous match returns False (no swap)."""
    s_nums = _numbers(sentence)
    cand_nums = _numbers(_row_text(candidate))
    if s_nums:
        if not s_nums.issubset(cand_nums):
            return False
    # keyword corroboration: the candidate must share meaningful terms with the sentence.
    s_kw = _keywords(sentence)
    cand_kw = _keywords(_row_text(candidate))
    if not s_kw:
        return bool(s_nums) and s_nums.issubset(cand_nums)
    overlap = len(s_kw & cand_kw)
    return overlap >= max(2, len(s_kw) // 10)


def reanchor_citation(
    *,
    sentence: str,
    current_ev_id: "str | None",
    evidence_pool: "Mapping[str, Any] | Sequence[Any]",
    id_of: "Optional[Callable[[Any], str]]" = None,
) -> "str | None":
    """Return the ev-id the sentence SHOULD cite: the current id UNCHANGED unless a strictly-more-
    primary pool row grounds the SAME fact, in which case that row's id. Pure; never raises.

    ``evidence_pool`` may be a mapping ``ev_id -> row`` or a sequence of rows (then ``id_of`` must
    extract each row's id, defaulting to ``row['ev_id']`` / ``row.ev_id``). OFF (default) or no
    resolvable current row => returns ``current_ev_id`` unchanged (byte-identical)."""
    if not reanchor_enabled():
        return current_ev_id
    if not current_ev_id:
        return current_ev_id

    # Normalize the pool to an (id, row) list.
    if isinstance(evidence_pool, Mapping):
        items = list(evidence_pool.items())
    else:
        def _default_id(r: "Any") -> str:
            return str(_get(r, "ev_id", "id") or "")
        _idf = id_of or _default_id
        items = [(_idf(r), r) for r in (evidence_pool or [])]
    by_id = {str(i): r for (i, r) in items if str(i)}

    current = by_id.get(str(current_ev_id))
    if current is None:
        return current_ev_id  # can't compare -> leave as-is (fail-open)

    best_id = str(current_ev_id)
    best_row = current
    for cand_id, cand in items:
        cand_id = str(cand_id)
        if not cand_id or cand_id == str(current_ev_id) or cand is current:
            continue
        if is_more_primary(cand, best_row) and _same_fact(sentence, current, cand):
            best_id, best_row = cand_id, cand

    if best_id != str(current_ev_id):
        logger.info(
            "[citation_reanchor] LEVER B: re-anchored citation %s -> %s "
            "(same fact, stronger primary source) BEFORE strict_verify",
            current_ev_id, best_id,
        )
    return best_id


def reanchor_sentences(
    sentences: "Sequence[tuple[str, str | None]]",
    evidence_pool: "Mapping[str, Any] | Sequence[Any]",
    id_of: "Optional[Callable[[Any], str]]" = None,
) -> "list[tuple[str, str | None]]":
    """Batch helper: re-anchor a list of ``(sentence_text, cited_ev_id)`` pairs. Returns a NEW
    list with each cited id possibly swapped to a stronger primary (prose untouched). OFF (default)
    => returns pairs with UNCHANGED ids (a shallow copy — byte-identical tokens)."""
    if not reanchor_enabled():
        return list(sentences)
    out: list[tuple[str, str | None]] = []
    for text, ev_id in sentences:
        out.append((text, reanchor_citation(
            sentence=text, current_ev_id=ev_id, evidence_pool=evidence_pool, id_of=id_of,
        )))
    return out

